const P="pylontech/stat";
const MOD="Deviceaddress";
const S={Deviceaddress:{t:"i",lo:1,hi:16},CYCLETimes:{t:"i",lo:0,hi:20000},SOH:{t:"i",lo:0,hi:100}};
function rej(r,d){node.warn("STAT verworfen: "+r+(d!==undefined?" | "+d:""));node.status({fill:"red",shape:"ring",text:r});return [null,{topic:msg.topic,payload:{error:r,detail:d,original:msg.payload}}];}
let x=msg.payload;
if(Buffer.isBuffer(x))x=x.toString("utf8");
if(typeof x==="string"){const s=x.trim();if(s.charAt(0)!=="{")return rej("kein JSON-Objekt",s.slice(0,60));try{x=JSON.parse(s);}catch(e){return rej("JSON-Parsefehler",e.message);}}
if(typeof x!=="object"||x===null||Array.isArray(x))return rej("Payload kein Objekt");
const t=String(msg.topic||"");
if(t.indexOf(P+"/")!==0)return rej("unerwartetes Topic",t);
const m=t.match(/\/(\d{1,2})$/);
if(!m)return rej("Topic-Form ungueltig",t);
const tm=parseInt(m[1],10);
for(const k of Object.keys(x))if(!Object.prototype.hasOwnProperty.call(S,k))return rej("unbekanntes Feld '"+k+"'");
const c={};
for(const k of Object.keys(S)){
  if(!Object.prototype.hasOwnProperty.call(x,k))return rej("Feld fehlt: "+k);
  const r=S[k];let v=x[k];
  if(typeof v==="string")v=v.trim();
  const n=Number(v);
  if(v===""||v===null||typeof v==="boolean"||!isFinite(n))return rej("nicht-numerisch: "+k,x[k]);
  if(r.t==="i"&&!Number.isInteger(n))return rej(k+" nicht ganzzahlig",x[k]);
  if(n<r.lo||n>r.hi)return rej(k+" ausserhalb ["+r.lo+".."+r.hi+"]",x[k]);
  c[k]=n;
}
if(c[MOD]!==tm)return rej(MOD+" != Topic-Modul",c[MOD]+" vs "+tm);
msg.payload=c;
node.status({fill:"green",shape:"dot",text:"ok M"+tm});
return [msg,null];
